from __future__ import annotations
from abc import ABC, abstractmethod


class FileSystemItem(ABC):
    @abstractmethod
    def get_name(self) -> str:
        pass

    @abstractmethod
    def get_size(self) -> int:
        pass

    @abstractmethod
    def print(self, indent: str = '') -> None:
        pass


class File(FileSystemItem):
    def __init__(self, name: str, size: int) -> None:
        self._name = name
        self._size = size

    def get_name(self) -> str:
        return self._name

    def get_size(self) -> int:
        return self._size

    def print(self, indent: str = '') -> None:
        print(f"{indent}[file] {self._name} ({self._size} KB)")


class Directory(FileSystemItem):
    def __init__(self, name: str) -> None:
        self._name = name
        self._children: list[FileSystemItem] = []

    def add(self, item: FileSystemItem) -> 'Directory':
        self._children.append(item)
        return self

    def remove(self, item: FileSystemItem) -> None:
        self._children.remove(item)

    def get_name(self) -> str:
        return self._name

    def get_size(self) -> int:
        return sum(c.get_size() for c in self._children)

    def print(self, indent: str = '') -> None:
        print(f"{indent}[dir] {self._name}/")
        for child in self._children:
            child.print(indent + '  ')


# Usage — client treats files and directories uniformly
root = Directory('project')
src = Directory('src')
tests = Directory('tests')

src.add(File('main.py', 12)).add(File('app.py', 34))
tests.add(File('test_app.py', 8))
root.add(src).add(tests).add(File('requirements.txt', 2))

root.print()
# [dir] project/
#   [dir] src/
#     [file] main.py (12 KB)
#     [file] app.py (34 KB)
#   [dir] tests/
#     [file] test_app.py (8 KB)
#   [file] requirements.txt (2 KB)

print(f"Total size: {root.get_size()} KB")  # Total size: 56 KB
